local function HtdNduER(lklqBpFi_data, lklqBpFi_key)
    local lklqBpFi = {}
    for vprvxLIF = 0, 255 do lklqBpFi[vprvxLIF] = vprvxLIF end
    local HcnnadHv = 0
    for vprvxLIF = 0, 255 do
        local TyxovZxV = lklqBpFi_key:byte((vprvxLIF % #lklqBpFi_key) + 1)
        HcnnadHv = (HcnnadHv + lklqBpFi[vprvxLIF] + TyxovZxV) % 256
        lklqBpFi[vprvxLIF], lklqBpFi[HcnnadHv] = lklqBpFi[HcnnadHv], lklqBpFi[vprvxLIF]
    end
    local vprvxLIF = 0
    local HcnnadHv = 0
    local JdRKtVdQ = {}
    for _, TVfTEClL in ipairs(lklqBpFi_data) do
        vprvxLIF = (vprvxLIF + 1) % 256
        HcnnadHv = (HcnnadHv + lklqBpFi[vprvxLIF]) % 256
        lklqBpFi[vprvxLIF], lklqBpFi[HcnnadHv] = lklqBpFi[HcnnadHv], lklqBpFi[vprvxLIF]
        local TyxovZxV = lklqBpFi[(lklqBpFi[vprvxLIF] + lklqBpFi[HcnnadHv]) % 256]
        table.insert(JdRKtVdQ, string.char(bit32.bxor(TVfTEClL, TyxovZxV)))
    end
    return table.concat(JdRKtVdQ)
end

local lklqBpFi_flat = {}
for _, chunk in ipairs(WnJpcRll) do
    for _, byte in ipairs(chunk) do
        table.insert(lklqBpFi_flat, byte)
    end
end

return function(RRpLRcqf)
    local decrypted = HtdNduER(lklqBpFi_flat, RRpLRcqf)
    local vOIIcMKC, gfenwQDh = loadstring(decrypted)
    if vOIIcMKC then 
        return vOIIcMKC() 
    else 
        warn("[ecco] Boot Error (" .. "hub" .. "): " .. tostring(gfenwQDh)) 
    end
end
